#!/usr/bin/env node
'use strict';

const fs = require('fs');
const path = require('path');

// ---------------------------------------------------------------------------
// FixBroken OS — Style Guide Generator
// ---------------------------------------------------------------------------
// Reads the manifest (generated by generate-manifest.js) and produces
// a comprehensive living style guide HTML page at /design/generated.html
//
// The hand-maintained /design/index.html stays as-is — this generated page
// is a machine-complete reference that is always in sync with the CSS.
// ---------------------------------------------------------------------------

const REPO_ROOT = path.resolve(__dirname, '..');
const MANIFEST_PATH = path.join(REPO_ROOT, 'public', 'design', 'fixbroken-os.manifest.json');
const OUTPUT_PATH = path.join(REPO_ROOT, 'public', 'design', 'generated.html');

function esc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function renderTokenGroup(groupName, tokens) {
  const isColor = groupName.startsWith('color');
  const rows = tokens.map(t => {
    const swatchHtml = isColor
      ? `<span class="sg-chip-color" style="background:var(${t.name});"></span>`
      : '';
    const desc = t.description ? `<span class="sg-desc">${esc(t.description)}</span>` : '';
    return `<div class="sg-swatch">${swatchHtml}<span class="sg-key">${esc(t.name)}</span><span class="sg-val">${esc(t.value)}</span>${desc}</div>`;
  }).join('\n                  ');

  const label = groupName.replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase());

  return `
            <div class="fb-stack fb-stack--tight">
              <span class="fb-label">${esc(label)}</span>
              <div class="fb-grid fb-grid--tight">
                  ${rows}
              </div>
            </div>`;
}

function renderComponent(comp) {
  return `
              <div class="fb-panel">
                <div class="fb-row fb-row--between" style="margin-bottom: var(--fb-s-2);">
                  <code class="fb-mono" style="color:var(--fb-signal); font-size: var(--fb-fs-14);">.${esc(comp.class)}</code>
                </div>
                <p style="color: var(--fb-text-dim); font-size: var(--fb-fs-14);">${esc(comp.description)}</p>
              </div>`;
}

function renderVoice(voice) {
  const useItems = voice.use.map(u => `<li>${esc(u)}</li>`).join('\n                    ');
  const avoidItems = voice.avoid.map(a => `<li>${esc(a)}</li>`).join('\n                    ');

  return `
            <div class="fb-grid fb-grid--2">
              <div class="fb-panel fb-panel--matrix">
                <span class="fb-label fb-label--matrix">USE</span>
                <ul style="margin-top: var(--fb-s-3); padding-left: 18px; list-style: disc;">
                    ${useItems}
                </ul>
              </div>
              <div class="fb-panel" style="border-color: color-mix(in srgb, var(--fb-red) 30%, var(--fb-hairline));">
                <span class="fb-label" style="color: var(--fb-red);">AVOID</span>
                <ul style="margin-top: var(--fb-s-3); padding-left: 18px; list-style: disc;">
                    ${avoidItems}
                </ul>
              </div>
            </div>`;
}

function renderKeyframes(keyframes) {
  return keyframes.map(k => `<span class="fb-chip fb-chip--signal">${esc(k)}</span>`).join('\n                  ');
}

function renderBreakpoints(breakpoints) {
  return breakpoints.map(bp => {
    const label = bp <= 380 ? 'narrow mobile' : bp <= 640 ? 'mobile' : 'tablet';
    return `<div class="fb-panel fb-panel--tight">
                <span class="fb-label">${bp}px</span>
                <p style="margin-top: var(--fb-s-1); font-size: var(--fb-fs-13); color: var(--fb-text-dim);">${label}</p>
              </div>`;
  }).join('\n              ');
}

function renderAllClasses(classes) {
  return classes.map(c => `<span class="fb-chip" style="font-size: var(--fb-fs-10);">.${esc(c)}</span>`).join('\n                  ');
}

function generate() {
  if (!fs.existsSync(MANIFEST_PATH)) {
    console.error('Manifest not found. Run: npm run generate:manifest');
    process.exit(1);
  }

  const manifest = JSON.parse(fs.readFileSync(MANIFEST_PATH, 'utf8'));
  const tokenGroups = Object.entries(manifest.tokens);
  const totalTokens = tokenGroups.reduce((s, [, arr]) => s + arr.length, 0);

  const tocEntries = [
    { id: 'tokens', label: 'Tokens' },
    { id: 'components', label: 'Components' },
    { id: 'classes', label: 'All Classes' },
    { id: 'voice', label: 'Voice' },
    { id: 'typography', label: 'Typography' },
    { id: 'motion', label: 'Motion' },
    { id: 'breakpoints', label: 'Breakpoints' },
    { id: 'rules', label: 'Rules' },
  ];

  const tocHtml = tocEntries.map(e =>
    `<a href="#${e.id}">${e.label}</a>`
  ).join('\n            ');

  const tokenSections = tokenGroups.map(([name, tokens]) => renderTokenGroup(name, tokens)).join('\n');

  const componentCards = manifest.components.map(renderComponent).join('\n');

  const html = `<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>FixBroken OS · Generated Reference</title>
<meta name="description" content="Auto-generated reference for FixBroken OS — every token, component, and rule extracted from the CSS.">
<meta name="theme-color" content="#05070a">
<link rel="icon" type="image/svg+xml" href="/favicon.svg">
<link rel="stylesheet" href="/design/fixbroken-os.css">
<style>
  .sg-section { scroll-margin-top: 80px; }
  .sg-swatch {
    display: flex; align-items: center; gap: var(--fb-s-3);
    padding: var(--fb-s-3);
    background: var(--fb-panel);
    border: 1px solid var(--fb-hairline);
    border-radius: var(--fb-r-2);
    font-family: var(--fb-font-mono);
    font-size: var(--fb-fs-12);
  }
  .sg-chip-color {
    width: 40px; height: 40px;
    border-radius: var(--fb-r-2);
    flex-shrink: 0;
    border: 1px solid var(--fb-hairline);
  }
  .sg-key { color: var(--fb-text-mute); text-transform: none; letter-spacing: var(--fb-tracking-wide); min-width: 180px; }
  .sg-val { color: var(--fb-text-loud); margin-left: auto; white-space: nowrap; }
  .sg-desc { color: var(--fb-text-mute); font-size: var(--fb-fs-11); margin-left: var(--fb-s-3); }
  .sg-toc {
    position: sticky; top: calc(var(--fb-nav-h) + var(--fb-s-4));
    align-self: start;
  }
  .sg-toc a {
    display: block; padding: 4px 0;
    color: var(--fb-text-mute);
    font-family: var(--fb-font-mono);
    font-size: var(--fb-fs-12);
    letter-spacing: var(--fb-tracking-wide);
    text-transform: uppercase;
    border-left: 1px solid var(--fb-hairline);
    padding-left: var(--fb-s-3);
    transition: color var(--fb-t-fast), border-color var(--fb-t-fast);
  }
  .sg-toc a:hover { color: var(--fb-signal); border-color: var(--fb-signal); }
  .sg-layout {
    display: grid;
    grid-template-columns: 180px minmax(0, 1fr);
    gap: var(--fb-s-8);
  }
  .sg-class-grid {
    display: flex; flex-wrap: wrap; gap: var(--fb-s-1);
  }
  @media (max-width: 960px) {
    .sg-layout { grid-template-columns: minmax(0, 1fr); }
    .sg-toc { position: static; display: flex; gap: var(--fb-s-2); flex-wrap: wrap; }
    .sg-toc a { border-left: 0; border: 1px solid var(--fb-hairline); padding: 6px 10px; border-radius: 999px; }
  }
</style>
</head>
<body>

<div class="fb-grid-bg"></div>
<div class="fb-scanline"></div>

<div class="fb-shell">

  <nav class="fb-nav">
    <div class="fb-nav__inner">
      <a href="/" class="fb-nav__brand">fixbroken.ai</a>
      <div class="fb-nav__links">
        <a class="fb-nav__link" href="/">System</a>
        <a class="fb-nav__link" href="/design/">Design</a>
        <a class="fb-nav__link fb-nav__link--active" href="/design/generated.html">Reference</a>
        <a class="fb-nav__link" href="mailto:hello@fixbroken.ai">Signal</a>
      </div>
    </div>
  </nav>

  <main>

    <section class="fb-section fb-section--loose" style="position:relative; overflow:hidden;">
      <div class="fb-mcp-cone" style="--cone-h: 400px;"></div>
      <div class="fb-container" style="position:relative;">
        <div class="fb-stack">
          <span class="fb-kicker">System · Auto-Generated Reference</span>
          <h1 class="fb-display">FixBroken <em>OS.</em></h1>
          <p class="fb-lede">
            Machine-generated from <code class="fb-mono" style="color:var(--fb-signal);">fixbroken-os.css</code> and <code class="fb-mono" style="color:var(--fb-signal);">brand.md</code>. ${totalTokens} tokens. ${manifest.components.length} components. ${manifest.allClasses.length} classes. Always current.
          </p>
          <div class="fb-row fb-row--wrap" style="gap: var(--fb-s-2);">
            <span class="fb-chip fb-chip--signal">v${esc(manifest.version)}</span>
            <span class="fb-chip fb-chip--matrix">auto-generated</span>
            <span class="fb-chip">${new Date(manifest.generated).toISOString().slice(0, 10)}</span>
          </div>
        </div>
      </div>
    </section>

    <section class="fb-section">
      <div class="fb-container">
        <div class="sg-layout">

          <aside class="sg-toc">
            ${tocHtml}
          </aside>

          <div class="fb-stack fb-stack--loose">

            <!-- TOKENS -->
            <div id="tokens" class="sg-section fb-stack">
              <span class="fb-kicker">Tokens</span>
              <h2>${totalTokens} design tokens.</h2>
              ${tokenSections}
            </div>

            <!-- COMPONENTS -->
            <div id="components" class="sg-section fb-stack">
              <span class="fb-kicker">Components</span>
              <h2>${manifest.components.length} documented components.</h2>
              <div class="fb-grid fb-grid--2">
                ${componentCards}
              </div>
            </div>

            <!-- ALL CLASSES -->
            <div id="classes" class="sg-section fb-stack">
              <span class="fb-kicker">All Classes</span>
              <h2>${manifest.allClasses.length} .fb-* classes.</h2>
              <div class="sg-class-grid">
                  ${renderAllClasses(manifest.allClasses)}
              </div>
            </div>

            <!-- VOICE -->
            <div id="voice" class="sg-section fb-stack">
              <span class="fb-kicker">Voice</span>
              <h2>How the system talks.</h2>
              ${renderVoice(manifest.voice)}
            </div>

            <!-- TYPOGRAPHY -->
            <div id="typography" class="sg-section fb-stack">
              <span class="fb-kicker">Typography</span>
              <h2>${manifest.typography.families.length} families. No compromise.</h2>
              ${manifest.typography.families.map(f => `
              <div class="fb-panel">
                <span class="fb-label">${esc(f.family)}</span>
                <p style="margin-top: var(--fb-s-2); color: var(--fb-text-dim);">${esc(f.usage)}</p>
              </div>`).join('\n')}
              <p class="fb-text-mute" style="font-family: var(--fb-font-mono); font-size: var(--fb-fs-12);">${esc(manifest.typography.rule)}</p>
            </div>

            <!-- MOTION -->
            <div id="motion" class="sg-section fb-stack">
              <span class="fb-kicker">Motion</span>
              <h2>${manifest.keyframes.length} keyframes.</h2>
              <div class="fb-row fb-row--wrap" style="gap: var(--fb-s-2);">
                  ${renderKeyframes(manifest.keyframes)}
              </div>
            </div>

            <!-- BREAKPOINTS -->
            <div id="breakpoints" class="sg-section fb-stack">
              <span class="fb-kicker">Responsive</span>
              <h2>${manifest.breakpoints.length} breakpoints.</h2>
              <div class="fb-grid">
                ${renderBreakpoints(manifest.breakpoints)}
              </div>
            </div>

            <!-- RULES -->
            <div id="rules" class="sg-section fb-stack">
              <span class="fb-kicker">Rules</span>
              <h2>System constraints.</h2>
              <div class="fb-stack fb-stack--tight">
                ${Object.entries(manifest.rules).map(([k, v]) => `
                <div class="fb-panel fb-panel--tight">
                  <span class="fb-label">${esc(k)}</span>
                  <p style="margin-top: var(--fb-s-1); font-size: var(--fb-fs-14); color: var(--fb-text-dim);">${esc(Array.isArray(v) ? v.join(', ') : v)}</p>
                </div>`).join('\n')}
              </div>
            </div>

          </div>
        </div>
      </div>
    </section>

  </main>

  <footer class="fb-footer">
    <div class="fb-footer__row">
      <span>fixbroken.ai · FixBroken OS v${esc(manifest.version)}</span>
      <span>auto-generated · ${new Date(manifest.generated).toISOString().slice(0, 19)}Z</span>
      <span class="fb-status">system online</span>
    </div>
  </footer>

</div>

</body>
</html>
`;

  fs.writeFileSync(OUTPUT_PATH, html);
  console.log(`✓ Style guide generated: ${OUTPUT_PATH}`);
  console.log(`  ${totalTokens} tokens, ${manifest.components.length} components, ${manifest.allClasses.length} classes`);
}

generate();
